+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { isRelation } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { Trait, TraitRecord, TraitValue } from '../trait/types';
+import type { World } from '../world';
+
+export const $aspect = Symbol.for('koota.aspect');
+
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: Record<string, unknown>;
+};
+
+type AspectRecord<T extends readonly Trait[]> = UnionToIntersection<TraitRecord<T[number]>>;
+type UnionToIntersection<T> = (T extends unknown ? (value: T) => void : never) extends (
+    value: infer Result
+) => void
+    ? Result
+    : never;
+
+let aspectId = 0;
+
+export function createAspect<T extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: T
+): Aspect<FlattenAspects<T>> {
+    const traits = inputs.flatMap((input) => (isAspect(input) ? input.traits : [input])) as FlattenAspects<T>;
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+
+    for (const trait of traits) {
+        if (isRelation(trait[$internal].relation)) {
+            throw Error('Aspects cannot contain relation traits');
+        }
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) throw Error(`Aspect field "${field}" is defined by multiple traits`);
+            fields.add(field);
+            schema[field] = trait.schema[field];
+        }
+    }
+
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits, schema });
+}
+
+type FlattenAspect<T> = T extends Aspect<infer Traits> ? Traits[number] : T extends Trait ? T : never;
+export type FlattenAspects<T extends readonly unknown[]> = { [K in keyof T]: FlattenAspect<T[K]> };
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect<T extends Aspect>(world: World, entity: Entity, aspect: T): AspectRecord<T['traits']> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    return Object.assign({}, ...aspect.traits.map((trait) => getTrait(world, entity, trait))) as AspectRecord<T['traits']>;
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown>) {
+    for (const trait of aspect.traits) {
+        const part = pickTraitFields(trait, value);
+        if (Object.keys(part).length) setTrait(world, entity, trait, part as TraitValue<any>, true);
+    }
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown> = {}) {
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, pickTraitFields(trait, value)]);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+export function pickTraitFields(trait: Trait, value: Record<string, unknown>) {
+    const result: Record<string, unknown> = {};
+    for (const field of Object.keys(trait.schema)) if (field in value) result[field] = value[field];
+    return result;
+}
